   171	function EditProjectModal({ project, onClose, onSave, busy }: { project: Project; onClose: () => void; onSave: (data: Partial<Project>) => Promise<void>; busy: boolean }) {
   172	  const [title,  setTitle]  = useState(project.title);
   173	  const [status, setStatus] = useState(project.status);
   174	  const [desc,   setDesc]   = useState(project.description ?? '');
