   185	            <div className="field"><label>Status</label>
   186	              <select className="input select" value={status} onChange={e => setStatus(e.target.value)}>
   187	                <option value="draft">Draft</option>
   188	                <option value="active">Active</option>
   189	                <option value="done">Done</option>
   190	                <option value="archived">Archived</option>
   191	              </select>
   192	            </div>
   193	            <div className="field"><label>Description</label><textarea className="input" rows={3} value={desc} onChange={e => setDesc(e.target.value)} /></div>
   194	            <div className="modal-foot" style={{ padding: 0, border: 0 }}>
   195	              <button type="button" className="btn btn-ghost" onClick={onClose}>Cancel</button>
